// Contract G2 — input {key, tenant_id} (optional workflow). Callable two ways:
//  - Execute Workflow node: fields arrive flat on the item.
//  - POST /webhook/idempotency-check: n8n wraps the body under `.body`.
const in0 = $input.first().json || {};
const src = in0.body || in0;

const key = src.key;
if (!key) {
  // Fail loud so the global error workflow (Contract G1) catches a malformed caller.
  throw new Error('idempotency-check: missing key');
}

return [{
  json: {
    key: key,
    tenant_id: src.tenant_id || null,
    workflow: src.workflow || null,
    supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, ''),
    service_key: $env.SUPABASE_SERVICE_KEY || ''
  }
}];

