// INSERT ... ON CONFLICT DO NOTHING via PostgREST:
//   new insert  -> body is the inserted row  -> [{...}] -> dup=false
//   conflict    -> nothing inserted           -> []      -> dup=true
// fullResponse=true keeps a single wrapper item even when body is [] (an empty
// array body would otherwise split into zero items and starve the last node).
const resp = $('Insert Key').first().json || {};
const rows = resp.body;
const dup = Array.isArray(rows) ? rows.length === 0 : !rows;
const norm = $('Normalize Input').first().json;
return [{ json: { key: norm.key, tenant_id: norm.tenant_id, dup: dup } }];
